import { useState } from 'react';
import { Link } from 'react-router-dom';
import SEO from './SEO';
import { authAPI } from '../services/api';

const ForgotPassword = ({ theme, toggleTheme }) => {
    const [email, setEmail] = useState('');
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!email) { setError('Email is required'); return; }
        if (!/\S+@\S+\.\S+/.test(email)) { setError('Enter a valid email'); return; }
        setLoading(true); setError(''); setSuccess(false);
        try {
            await authAPI.forgotPassword(email);
            setSuccess(true);
        } catch (err) { setError(err.message || 'Failed to send reset email.'); }
        finally { setLoading(false); }
    };

    return (
        <>
            <SEO title="Forgot Password | CodeNexus Studio" description="Reset your CodeNexus Studio account password." canonical="https://codenexusstudio.vercel.app/forgot-password" />

            <div className="min-h-screen flex flex-col bg-[var(--bg-dark)] relative overflow-hidden">
                <div className="absolute rounded-full z-0 animate-[blobFloat_12s_infinite_alternate] pointer-events-none w-[550px] h-[550px] -top-[15%] -left-[12%] bg-[radial-gradient(circle,var(--primary-glow),transparent_70%)]"></div>
                <div className="absolute rounded-full z-0 animate-[blobFloat_12s_infinite_alternate] pointer-events-none w-[480px] h-[480px] -bottom-[10%] -right-[10%] bg-[radial-gradient(circle,rgba(168,85,247,0.35),transparent_70%)] [animation-delay:-6s]"></div>

                <header className="flex items-center justify-between py-5 px-10 max-sm:px-5 relative z-10">
                    <Link to="/" className="font-['Outfit'] text-2xl font-extrabold text-[var(--text-main)] no-underline tracking-[-0.5px] transition-opacity duration-300 hover:opacity-80">
                        Code<span className="bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] bg-clip-text [-webkit-text-fill-color:transparent]">Nexus</span>.
                    </Link>
                    <button className="bg-[rgba(255,255,255,0.05)] border border-[var(--glass-border)] rounded-full w-10 h-10 text-[1.1rem] cursor-pointer transition-all duration-300 flex items-center justify-center color-[var(--text-main)] hover:scale-105 hover:bg-[rgba(255,255,255,0.1)] hover:border-[var(--primary)]" onClick={toggleTheme} aria-label="Toggle theme">
                        {theme === 'light' ? '🌞' : '🌙'}
                    </button>
                </header>

                <main className="flex-1 flex items-center justify-center py-8 px-4 relative z-[5]">
                    <div className="bg-[var(--glass-bg)] border border-[var(--glass-border)] backdrop-blur-[20px] rounded-3xl p-11 max-sm:p-8 w-full max-w-[440px] shadow-[0_8px_32px_rgba(0,0,0,0.35),inset_0_0_0_1px_var(--glass-border)] animate-[cardFadeIn_0.6s_cubic-bezier(0.22,1,0.36,1)]">
                        <div className="w-[60px] h-[60px] rounded-2xl bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] flex items-center justify-center mx-auto mb-6 shadow-[0_8px_24px_var(--primary-glow)]">
                            <svg className="w-7 h-7 text-white" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M12 2C6.47715 2 2 6.47715 2 12C2 17.5228 6.47715 22 12 22C17.5228 22 22 17.5228 22 12C22 6.47715 17.5228 2 12 2Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                <path d="M12 16V12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                <path d="M12 8H12.01" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                            </svg>
                        </div>

                        <h1 className="text-[1.85rem] max-sm:text-[1.6rem] font-extrabold text-center text-[var(--text-main)] mb-1 tracking-[-0.5px]">Reset Password</h1>
                        <p className="text-center color-[var(--text-muted)] text-[0.95rem] mb-8">Enter your email to receive a reset link</p>

                        {success ? (
                            <div className="text-center mb-5">
                                <p className="text-emerald-500 mb-4">Password reset link has been sent to your email!</p>
                                <Link to="/login" className="mt-2 py-[0.85rem] px-6 bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] text-white border-none rounded-xl text-base font-bold font-['Outfit'] cursor-pointer inline-flex items-center justify-center transition-all duration-250 shadow-[0_4px_20px_var(--primary-glow)] hover:opacity-90 hover:-translate-y-0.5 hover:shadow-[0_8px_28px_var(--primary-glow)] no-underline w-full">Back to Login</Link>
                            </div>
                        ) : (
                            <form onSubmit={handleSubmit} className="flex flex-col gap-5" noValidate>
                                <div className="flex flex-col gap-2 focus-within:[&>label]:text-[var(--primary)]">
                                    <label htmlFor="email" className="text-[0.875rem] font-semibold text-[var(--text-muted)] pl-0.5 transition-colors duration-300">Email Address</label>
                                    <div className="relative flex items-center">
                                        <span className="absolute left-3.5 flex items-center text-[var(--text-muted)] pointer-events-none">
                                            <svg className="w-[17px] h-[17px]" viewBox="0 0 24 24" fill="none"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /><polyline points="22,6 12,13 2,6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
                                        </span>
                                        <input id="email" type="email" placeholder="you@example.com" value={email} onChange={(e) => { setEmail(e.target.value); setError(''); }} autoComplete="email" className={`w-full py-3 pr-4 pl-11 bg-[rgba(255,255,255,0.05)] border-2 ${error ? 'border-red-400 bg-[rgba(248,113,113,0.05)]' : 'border-[var(--glass-border)] focus:border-[var(--primary)] focus:bg-[rgba(99,102,241,0.05)] focus:shadow-[0_0_0_3px_var(--primary-glow)]'} rounded-xl text-[var(--text-main)] text-[0.95rem] font-['Outfit'] outline-none transition-all duration-300 placeholder:text-[var(--text-muted)] placeholder:opacity-70`} />
                                    </div>
                                    {error && <span className="text-[0.8rem] text-red-400 pl-0.5">{error}</span>}
                                </div>

                                <button type="submit" className="mt-2 py-[0.85rem] px-6 bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] text-white border-none rounded-xl text-base font-bold font-['Outfit'] cursor-pointer flex items-center justify-center gap-2 transition-all duration-250 shadow-[0_4px_20px_var(--primary-glow)] hover:not(:disabled):opacity-90 hover:not(:disabled):-translate-y-0.5 hover:not(:disabled):shadow-[0_8px_28px_var(--primary-glow)] disabled:opacity-70 disabled:cursor-not-allowed group" disabled={loading}>
                                    {loading ? <span className="w-[22px] h-[22px] border-4 border-white/30 border-t-white rounded-full animate-spin"></span> : <>Send Reset Link <span className="inline-block transition-transform duration-300 group-hover:translate-x-1">→</span></>}
                                </button>

                                <div className="flex justify-center mt-4">
                                    <Link to="/login" className="text-[var(--primary)] no-underline font-semibold transition-opacity duration-300 hover:opacity-75 hover:underline">← Back to Login</Link>
                                </div>
                            </form>
                        )}
                    </div>
                </main>
            </div>
        </>
    );
};

export default ForgotPassword;
